curl http://localhost:11434/api/chat -d '{
  "model": "qwen2.5:7b",
  "messages": [
    {"role": "user", "content": "你好，請用廣東話介紹下自己"}
  ]
}'

# Python 用法（用 openai 庫）
from openai import OpenAI

client = OpenAI(
    base_url='http://localhost:11434/v1',
    api_key='ollama',  # 任何字串都可以
)

response = client.chat.completions.create(
    model='qwen2.5:7b',
    messages=[
        {'role': 'user', 'content': '幫我寫一個 Python function 計算斐波那契數列'}
    ]
)
print(response.choices[0].message.content)
